insert into public.bot_knowledge_entries (slug, title, body, tags, language, is_active)
values
  ($$brand-personality$$, $$شخصية الشيف الذكي$$, $$أنت الشيف الذكي لمطبخ اليوم. تحدث دائماً بأسلوب مهذب وراقٍ وواضح ومختصر، ويمثل مطبخ اليوم كعلامة أردنية رائدة في الطبخ المنزلي الأصيل والجودة العالية والكرم الأردني. لا تخترع أسعاراً أو عروضاً أو معلومات غير موجودة. عند نقص المعلومات اسأل سؤالاً واحداً فقط وهو الأهم.$$, ARRAY[$$شخصية البوت$$, $$الشيف الذكي$$, $$prompt$$, $$system prompt$$, $$مطبخ اليوم$$, $$هوية العلامة$$, $$راقي$$, $$مهذب$$]::text[], 'ar', true),
  ($$greeting-default$$, $$رسالة الترحيب الأساسية$$, $$أهلاً وسهلاً بكم في مطبخ اليوم 🌿
نقدم أشهى الأطباق المنزلية بنكهات أصيلة وجودة عالية.
يسعدني مساعدتك في اختيار الطلب المناسب، كيف يمكنني خدمتك اليوم؟$$, ARRAY[$$مرحبا$$, $$السلام عليكم$$, $$صباح الخير$$, $$مساء الخير$$, $$ترحيب$$, $$اهلا$$, $$أهلاً$$]::text[], 'ar', true),
  ($$available-overview$$, $$نظرة عامة على المتوفر$$, $$متوفر لدينا عدة أطباق منزلية مميزة مثل: المقلوبة، المسخن، المفتول، المنسف، اليالنجي، الشيشبرك، شيخ المحشي، والكبة اللبنية. كما تتوفر بعض المقالي والمفرزات والعروض العائلية. اذكر لي عدد الأشخاص أو الصنف المطلوب وسأرشدك مباشرة.$$, ARRAY[$$شو عندكم$$, $$شو متوفر$$, $$شو الأكل اليوم$$, $$في أكل جاهز$$, $$شو عندكم مطبوخ$$, $$المتوفر$$, $$الأكلات المتوفرة$$]::text[], 'ar', true),
  ($$delivery-general$$, $$معلومة التوصيل$$, $$نعم يتوفر توصيل 🌿
يرجى إرسال المنطقة أو الموقع حتى نحدد رسوم ووقت التوصيل بدقة.$$, ARRAY[$$توصيل$$, $$دليفري$$, $$بتوصلوا$$, $$يوصل$$, $$رسوم التوصيل$$, $$وقت التوصيل$$]::text[], 'ar', true),
  ($$location-main$$, $$الموقع$$, $$موقعنا في عمّان – أم السماق.$$, ARRAY[$$وين موقعكم$$, $$وين مكانكم$$, $$وين عنوانكم$$, $$موقعكم$$, $$عنوانكم$$, $$أم السماق$$]::text[], 'ar', true),
  ($$cooked-food$$, $$هل الأكل مطبوخ$$, $$نعم، الأكل مطبوخ وجاهز للأكل مباشرة. كما يتوفر بعض الأصناف غير المطبوخة (جاهزة للطبخ) حسب الطلب.$$, ARRAY[$$هل الأكل مطبوخ$$, $$الاكل مطبوخ$$, $$أكل مطبوخ$$, $$جاهز للأكل$$, $$غير مطبوخ$$]::text[], 'ar', true),
  ($$tracking-help$$, $$متابعة الطلب أو الشكوى$$, $$نعتذر عن ذلك 🌿
يرجى إرسال رقم الطلب أو رقم الهاتف حتى نتابع الموضوع مباشرة وبأسرع وقت.$$, ARRAY[$$طلبي وين$$, $$وين طلبي$$, $$تأخر الطلب$$, $$وصل ناقص$$, $$شكوى$$, $$الأكل بارد$$, $$ما وصلني$$]::text[], 'ar', true),
  ($$count-warak-enab$$, $$عدد حبات ورق العنب في الكيلو$$, $$كيلو ورق العنب يحتوي تقريباً على 60 – 65 حبة.$$, ARRAY[$$كم حبة في كيلو ورق العنب$$, $$كم حبة ورق عنب$$, $$عدد ورق العنب$$, $$60 65 حبة$$]::text[], 'ar', true),
  ($$count-kousa$$, $$عدد حبات الكوسا في الكيلو$$, $$كيلو الكوسا يحتوي تقريباً على 10 – 12 حبة حسب الوزن، وحجم الكوسا وسط.$$, ARRAY[$$كم حبة كوسا في الكيلو$$, $$عدد الكوسا$$, $$كيلو كوسا كم حبة$$]::text[], 'ar', true),
  ($$count-batenjan$$, $$عدد حبات الباذنجان في الكيلو$$, $$كيلو الباذنجان يحتوي تقريباً على 10 – 12 حبة حسب الوزن، وحجم الباذنجان وسط.$$, ARRAY[$$كم حبة باذنجان في الكيلو$$, $$عدد الباذنجان$$, $$كيلو باذنجان كم حبة$$]::text[], 'ar', true),
  ($$count-yalanji$$, $$عدد حبات اليالنجي في الكيلو$$, $$كيلو اليالنجي بعد اللف يحتوي تقريباً على 40 – 44 حبة.$$, ARRAY[$$كم حبة يالنجي في الكيلو$$, $$عدد اليالنجي$$, $$كيلو يالنجي كم حبة$$]::text[], 'ar', true),
  ($$raw-warak-enab$$, $$كيلو ورق عنب غير مطبوخ$$, $$كيلو ورق العنب غير المطبوخ سعره 8 دنانير.$$, ARRAY[$$ورق عنب غير مطبوخ$$, $$كيلو ورق عنب غير مطبوخ$$, $$سعر ورق عنب غير مطبوخ$$, $$8 دنانير$$]::text[], 'ar', true),
  ($$raw-kousa$$, $$كيلو كوسا غير مطبوخ$$, $$كيلو الكوسا غير المطبوخ سعره 5 دنانير.$$, ARRAY[$$كوسا غير مطبوخ$$, $$كيلو كوسا غير مطبوخ$$, $$سعر كوسا غير مطبوخ$$]::text[], 'ar', true),
  ($$raw-batenjan$$, $$كيلو باذنجان غير مطبوخ$$, $$كيلو الباذنجان غير المطبوخ سعره 5 دنانير.$$, ARRAY[$$باذنجان غير مطبوخ$$, $$كيلو باذنجان غير مطبوخ$$, $$سعر باذنجان غير مطبوخ$$]::text[], 'ar', true),
  ($$raw-yalanji$$, $$كيلو يالنجي غير مطبوخ$$, $$كيلو اليالنجي غير المطبوخ سعره 8 دنانير.$$, ARRAY[$$يالنجي غير مطبوخ$$, $$كيلو يالنجي غير مطبوخ$$, $$سعر يالنجي غير مطبوخ$$]::text[], 'ar', true),
  ($$raw-kousa-yalanji$$, $$كيلو كوسا يالنجي غير مطبوخ$$, $$كيلو كوسا يالنجي غير المطبوخ سعره 5 دنانير.$$, ARRAY[$$كوسا يالنجي غير مطبوخ$$, $$سعر كوسا يالنجي غير مطبوخ$$]::text[], 'ar', true),
  ($$raw-batenjan-yalanji$$, $$كيلو باذنجان يالنجي غير مطبوخ$$, $$كيلو باذنجان يالنجي غير المطبوخ سعره 5 دنانير.$$, ARRAY[$$باذنجان يالنجي غير مطبوخ$$, $$سعر باذنجان يالنجي غير مطبوخ$$]::text[], 'ar', true),
  ($$offer-ribs-romani-large$$, $$عرض ورق العنب والكوسا مع ريش روماني كبير$$, $$العرض الأول: كيلو ورق عنب + كيلو كوسا + 4 ريش + خيار باللبن. السعر 25 دينار، يكفي 3 – 4 أشخاص، ونوع اللحم روماني.$$, ARRAY[$$عرض ورق العنب والكوسا مع الريش$$, $$ريش روماني$$, $$العرض الكبير ريش روماني$$, $$25 دينار$$]::text[], 'ar', true),
  ($$offer-ribs-romani-small$$, $$عرض ورق العنب والكوسا مع ريش روماني صغير$$, $$العرض الثاني: نصف كيلو ورق عنب + نصف كيلو كوسا + 3 ريش + خيار باللبن. السعر 14 دينار، ويكفي شخصين، ونوع اللحم روماني.$$, ARRAY[$$العرض الصغير ريش روماني$$, $$عرض صغير ريش$$, $$14 دينار$$, $$شخصين$$]::text[], 'ar', true),
  ($$offer-ribs-baladi-large$$, $$عرض ورق العنب والكوسا مع ريش بلدي كبير$$, $$العرض الأول: كيلو ورق عنب + كيلو كوسا + 4 ريش + خيار باللبن. السعر 30 دينار، يكفي 3 – 4 أشخاص، ونوع اللحم بلدي.$$, ARRAY[$$عرض ورق عنب وكوسا بلدي$$, $$ريش بلدي$$, $$العرض الكبير بلدي$$, $$30 دينار$$]::text[], 'ar', true),
  ($$offer-ribs-baladi-small$$, $$عرض ورق العنب والكوسا مع ريش بلدي صغير$$, $$العرض الثاني: نصف كيلو ورق عنب + نصف كيلو كوسا + 3 ريش + خيار باللبن. السعر 17 دينار، ويكفي شخصين، ونوع اللحم بلدي.$$, ARRAY[$$العرض الصغير بلدي$$, $$عرض صغير لحم بلدي$$, $$17 دينار$$]::text[], 'ar', true),
  ($$offer-chicken-large$$, $$عرض ورق العنب والكوسا مع دجاج كبير$$, $$العرض الأول: كيلو ورق عنب + كيلو كوسا + دجاجة + خيار باللبن. السعر 21 دينار، ويكفي 3 – 4 أشخاص.$$, ARRAY[$$عرض مع دجاج$$, $$عرض ورق عنب وكوسا دجاج$$, $$21 دينار$$, $$يكفي 3 4 أشخاص$$]::text[], 'ar', true),
  ($$offer-chicken-small$$, $$عرض ورق العنب والكوسا مع دجاج صغير$$, $$العرض الثاني: نصف كيلو ورق عنب + نصف كيلو كوسا + نصف دجاجة + خيار باللبن. السعر 12 دينار، ويكفي شخصين.$$, ARRAY[$$العرض الصغير مع الدجاج$$, $$عرض صغير دجاج$$, $$12 دينار$$]::text[], 'ar', true),
  ($$maqloubeh-overview$$, $$عالم المقلوبة$$, $$الخضروات المستخدمة في المقلوبة: باذنجان + زهرة + بطاطا. متوفر مقلوبة على دجاجة أو دجاجتين أو 3 دجاجات، كما تتوفر مقلوبة لحم بلدي أو روماني حسب الكيلو.$$, ARRAY[$$المقلوبة$$, $$شو خضار المقلوبة$$, $$عالم المقلوبة$$]::text[], 'ar', true),
  ($$maqloubeh-1-chicken$$, $$مقلوبة على دجاجة$$, $$مقلوبة على دجاجة سعرها 11 دينار.$$, ARRAY[$$مقلوبة على دجاجة$$, $$سعر المقلوبة$$, $$مقلوبة دجاج$$, $$11 دينار$$]::text[], 'ar', true),
  ($$maqloubeh-2-chicken$$, $$مقلوبة على دجاجتين$$, $$مقلوبة على دجاجتين سعرها 19 دينار.$$, ARRAY[$$مقلوبة على دجاجتين$$, $$19 دينار$$, $$مقلوبة لشخصات اكثر$$]::text[], 'ar', true),
  ($$maqloubeh-3-chicken$$, $$مقلوبة على 3 دجاجات$$, $$مقلوبة على 3 دجاجات سعرها 25 دينار.$$, ARRAY[$$مقلوبة على 3 دجاجات$$, $$مقلوبة كبيرة$$, $$25 دينار$$]::text[], 'ar', true),
  ($$maqloubeh-addons$$, $$مقلوبة مع 2 لبن و2 سلطة$$, $$مقلوبة على دجاجة + 2 لبن + 2 سلطة، السعر 14 دينار.$$, ARRAY[$$مقلوبة مع لبن وسلطة$$, $$مقلوبة مع اضافات$$, $$14 دينار$$]::text[], 'ar', true),
  ($$maqloubeh-baladi$$, $$مقلوبة لحم بلدي$$, $$مقلوبة لحم بلدي: الكيلو 23 دينار، 2 كيلو 38 دينار، 3 كيلو 52 دينار. ويتم تقطيع الكيلو إلى 3 أو 4 قطع حسب طلب الزبون.$$, ARRAY[$$مقلوبة لحم بلدي$$, $$كيلو مقلوبة بلدي$$, $$23 دينار$$, $$38 دينار$$, $$52 دينار$$]::text[], 'ar', true),
  ($$maqloubeh-romani$$, $$مقلوبة لحم روماني$$, $$مقلوبة لحم روماني: الكيلو 17 دينار، 2 كيلو 28 دينار، 3 كيلو 38 دينار. ويتم تقطيع الكيلو إلى 3 أو 4 قطع حسب طلب الزبون.$$, ARRAY[$$مقلوبة لحم روماني$$, $$كيلو مقلوبة روماني$$, $$17 دينار$$, $$28 دينار$$, $$38 دينار$$]::text[], 'ar', true),
  ($$musakhan-1$$, $$مسخن على دجاجة$$, $$مسخن على دجاجة (4 أرغفة) سعره 11 دينار.$$, ARRAY[$$مسخن$$, $$مسخن على دجاجة$$, $$4 أرغفة$$, $$11 دينار$$]::text[], 'ar', true),
  ($$musakhan-2$$, $$مسخن على دجاجتين$$, $$مسخن على دجاجتين (8 أرغفة) سعره 19 دينار.$$, ARRAY[$$مسخن على دجاجتين$$, $$8 أرغفة$$, $$19 دينار$$]::text[], 'ar', true),
  ($$musakhan-3$$, $$مسخن على 3 دجاجات$$, $$مسخن على 3 دجاجات (12 رغيف) سعره 25 دينار.$$, ARRAY[$$مسخن على 3 دجاجات$$, $$12 رغيف$$, $$25 دينار$$]::text[], 'ar', true),
  ($$musakhan-extra-bread$$, $$رغيف إضافي للمسخن$$, $$أي رغيف إضافي للمسخن سعره 1 دينار.$$, ARRAY[$$رغيف إضافي$$, $$زيادة رغيف$$, $$كم سعر الرغيف الاضافي$$]::text[], 'ar', true),
  ($$maftoul-overview$$, $$عالم المفتول$$, $$مفتول على دجاجة: 11 دينار. مفتول على دجاجتين: 21 دينار. مفتول على 3 دجاجات: 25 دينار. كيلو مفتول مطبوخ وجاهز للأكل: 6 دنانير. كيلو مفتول غير مطبوخ: 4 دنانير.$$, ARRAY[$$المفتول$$, $$عالم المفتول$$, $$سعر المفتول$$]::text[], 'ar', true),
  ($$maftoul-soup$$, $$مكونات شوربة المفتول$$, $$شوربة المفتول تتكون من مرقة دجاج + حمص + بصل. ويمكن إضافة خضروات مثل بندورة أو بطاطا أو جزر أو كوسا مقابل زيادة 2 دينار. والمفتول نفسه يتكون من طحين + سميد + زيت زيتون.$$, ARRAY[$$شوربة المفتول$$, $$مكونات المفتول$$, $$مم يتكون المفتول$$, $$إضافة خضار$$]::text[], 'ar', true),
  ($$yalanji-overview$$, $$عالم اليالنجي$$, $$كيلو اليالنجي: 12 دينار. كوسا يالنجي: 6 دنانير. باذنجان يالنجي: 6 دنانير. ملفوف يالنجي: 8 دنانير. كما يتوفر يالنجي غير مطبوخ حسب الطلب.$$, ARRAY[$$اليالنجي$$, $$عالم اليالنجي$$, $$سعر اليالنجي$$]::text[], 'ar', true),
  ($$shishbarak-overview$$, $$عالم الشيشبرك$$, $$شيشبرك لشخصين + أرز: 10 دنانير (20 حبة). شيشبرك لـ 4 أشخاص + أرز: 16 دينار (40 حبة). شيشبرك لـ 6 أشخاص + أرز: 22 دينار (60 حبة). شيشبرك مفرز 50 حبة: 8 دنانير. نوع اللحم في الحشوة: لحم عجل بلدي.$$, ARRAY[$$شيشبرك$$, $$سعر الشيشبرك$$, $$شيشبرك مفرز$$, $$20 حبة$$, $$40 حبة$$, $$60 حبة$$]::text[], 'ar', true),
  ($$sheikh-overview$$, $$عالم شيخ المحشي$$, $$شيخ المحشي لشخصين + أرز: 10 دنانير (8 حبات). لـ 4 أشخاص + أرز: 16 دينار (16 حبة). لـ 6 أشخاص + أرز: 22 دينار (24 حبة). كيلو شيخ المحشي مفرز (12 حبة): 12 دينار. نوع اللحم: لحم عجل بلدي.$$, ARRAY[$$شيخ المحشي$$, $$شيخ محشي$$, $$سعر شيخ المحشي$$, $$8 حبات$$, $$16 حبة$$, $$24 حبة$$]::text[], 'ar', true),
  ($$kubbeh-labanieh-overview$$, $$عالم الكبة اللبنية$$, $$كبة لبنية لشخصين + أرز: 10 دنانير (8 حبات). كبة لبنية لـ 4 أشخاص + أرز: 16 دينار (16 حبة). كبة لبنية لـ 6 أشخاص + أرز: 22 دينار. كيلو كبة مفرزة (20 حبة): 10 دنانير. نوع اللحم: لحم عجل بلدي.$$, ARRAY[$$كبة لبنية$$, $$سعر الكبة اللبنية$$, $$كبة مفرزة$$, $$20 حبة$$]::text[], 'ar', true),
  ($$fried-overview$$, $$المقالي$$, $$حبة كبة مقلية: 0.75 دينار. 3 رولات مسخن: 1 دينار. سمبوسك جبنة مقلية: 0.40 دينار. سمبوسك لحمة مقلية: 0.40 دينار. سبرينغ رول مقلي: 0.50 دينار.$$, ARRAY[$$المقالي$$, $$كبة مقلية$$, $$سمبوسك$$, $$سبرينغ رول$$, $$رولات مسخن$$]::text[], 'ar', true),
  ($$frozen-overview$$, $$المفرزات$$, $$كيلو كبة (20 حبة): 10 دنانير. رولات مسخن (25 حبة): 8 دنانير. سمبوسك جبنة (25 حبة): 8 دنانير. سمبوسك لحمة (25 حبة): 10 دنانير. شيشبرك مفرز (50 حبة): 8 دنانير.$$, ARRAY[$$المفرزات$$, $$أكل مفرز$$, $$كبة مفرزة$$, $$سمبوسك مفرز$$, $$شيشبرك مفرز$$]::text[], 'ar', true),
  ($$frozen-saving-offer$$, $$عرض التوفير للمفرزات$$, $$عرض التوفير للمفرزات يحتوي على: 25 حبة كبة + 25 حبة سمبوسك جبنة + 25 حبة رول مسخن + 50 حبة شيشبرك. السعر 35 دينار.$$, ARRAY[$$عرض التوفير للمفرزات$$, $$عرض المفرزات$$, $$35 دينار$$, $$شو داخل عرض التوفير$$]::text[], 'ar', true),
  ($$mansaf-baladi$$, $$منسف لحم بلدي$$, $$منسف لحم بلدي: الكيلو 23 دينار، 2 كيلو 38 دينار، 3 كيلو 52 دينار. يتم تقطيع الكيلو إلى 3 أو 4 قطع حسب طلب الزبون.$$, ARRAY[$$منسف لحم بلدي$$, $$كيلو منسف بلدي$$, $$23 دينار$$, $$38 دينار$$, $$52 دينار$$]::text[], 'ar', true),
  ($$mansaf-romani$$, $$منسف لحم روماني$$, $$منسف لحم روماني: الكيلو 17 دينار، 2 كيلو 28 دينار، 3 كيلو 38 دينار. يتم تقطيع الكيلو إلى 3 أو 4 قطع حسب طلب الزبون.$$, ARRAY[$$منسف لحم روماني$$, $$كيلو منسف روماني$$, $$17 دينار$$, $$28 دينار$$, $$38 دينار$$]::text[], 'ar', true),
  ($$mansaf-chicken$$, $$منسف على دجاج$$, $$منسف على دجاجة: 11 دينار. منسف على دجاجتين: 19 دينار. منسف على 3 دجاجات: 25 دينار. والدجاج مشوي أو مسلوق حسب طلب الزبون.$$, ARRAY[$$منسف على دجاجة$$, $$منسف دجاج$$, $$الدجاج مشوي او مسلوق$$, $$11 دينار$$, $$19 دينار$$, $$25 دينار$$]::text[], 'ar', true),
  ($$banquets-overview$$, $$الولائم الكبيرة$$, $$للطلبات الكبيرة والولائم يمكن تجهيز ضلعة محشية، نصف خاروف، أو خاروف كامل. يرجى تحديد عدد الأشخاص والتاريخ المطلوب حتى ننسق الطلب بالشكل الأنسب.$$, ARRAY[$$ولائم$$, $$عزيمة$$, $$طلب كبير$$, $$الولائم الكبيرة$$, $$ضيوف$$]::text[], 'ar', true),
